// benches/sesame_overhead.rs
//
// Criterion benchmarks measuring SESAME per-request overhead, producing the
// table cited in ANSI/SCTE 130-9 §9.2. Measures each tier operation and the
// combined verify+open / seal+sign paths over representative ESAM payload sizes.
//
// Run:  cargo bench --bench sesame_overhead
// HTML reports land in target/criterion/. The Markdown summary for the paper is
// generated by scripts/bench_to_md (see docs/benchmarks.md).

use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion, Throughput};
use time::format_description::well_known::Rfc3339;
use time::OffsetDateTime;

use pois_esam_server::sesame::canonical;
use pois_esam_server::sesame::keys::{AeadKey, ChannelScope, HmacKey, StaticKeyProvider};
use pois_esam_server::sesame::message::{hex_encode, PROTOCOL_VERSION};
use pois_esam_server::sesame::replay::{InMemoryReplayCache, ReplayCache};
use pois_esam_server::sesame::tier1_hmac;
use pois_esam_server::sesame::tier2_authz;
use pois_esam_server::sesame::tier3_aead::{self, IV_LEN, KEY_LEN};
use pois_esam_server::sesame::{
    self, RequestContext, ResponseParams, SesameConfig, SesameHeaders, Tier,
};

const SIGN_KEY: &[u8] = b"sas-east-01-shared-secret-0123456789";
const ENC_KEY: [u8; KEY_LEN] = [0x42; KEY_LEN];
const TS: &str = "2026-02-24T18:00:00Z";
const NONCE: &str = "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6";
const SCOPE: &str = "channel=SportsFeed-East";
const PATH: &str = "/esam?channel=SportsFeed-East";

fn payload(size: usize) -> Vec<u8> {
    // A realistic-ish ESAM XML envelope padded to `size` bytes.
    let head = b"<?xml version=\"1.0\"?><SignalProcessingEvent acquisitionPointIdentity=\"sas-east-01\"><AcquiredSignal acquisitionSignalID=\"sig-001\"><BinaryData signalType=\"SCTE35\">";
    let tail = b"</BinaryData></AcquiredSignal></SignalProcessingEvent>";
    let mut v = Vec::with_capacity(size);
    v.extend_from_slice(head);
    while v.len() < size.saturating_sub(tail.len()) {
        v.push(b'A');
    }
    v.extend_from_slice(tail);
    v.truncate(size.max(head.len() + tail.len()));
    v
}

fn provider() -> StaticKeyProvider {
    StaticKeyProvider::new()
        .with_signing_key("sas-east-01", HmacKey(SIGN_KEY.to_vec()), ChannelScope::list(["SportsFeed-East"]))
        .with_signing_key("pois-primary", HmacKey(SIGN_KEY.to_vec()), ChannelScope::all())
        .with_aead_key("enc-sportsfeed-2026q1", AeadKey(ENC_KEY))
}

fn now() -> OffsetDateTime {
    OffsetDateTime::now_utc()
}

/// A `now` aligned to the fixed request timestamp `TS`, so the freshness check
/// passes and the full verify path is actually exercised (otherwise a stale
/// timestamp short-circuits before any crypto runs).
fn bench_now() -> OffsetDateTime {
    OffsetDateTime::parse(TS, &Rfc3339).unwrap()
}

/// Construct a fully-signed Tier-3 request (headers + ciphertext body).
fn signed_tier3_request(body: &[u8]) -> (SesameHeaders, Vec<u8>) {
    let iv = [0u8; IV_LEN];
    let aad = tier3_aead::aad_for_headers(PROTOCOL_VERSION, "sas-east-01", TS, NONCE, Some(SCOPE));
    let ct = tier3_aead::seal(&ENC_KEY, &iv, &aad, body).unwrap();
    let body_hash = canonical::body_hash_hex(&ct);
    let canon = canonical::request_canonical("POST", PATH, TS, NONCE, &body_hash, Some(SCOPE));
    let sig = tier1_hmac::sign(SIGN_KEY, &canon);
    let headers = SesameHeaders {
        version: Some(PROTOCOL_VERSION.to_string()),
        key_id: Some("sas-east-01".to_string()),
        timestamp: Some(TS.to_string()),
        nonce: Some(NONCE.to_string()),
        signature: Some(sig),
        scope: Some(SCOPE.to_string()),
        encrypted: true,
        enc_key_id: Some("enc-sportsfeed-2026q1".to_string()),
        iv: Some(hex_encode(&iv)),
    };
    (headers, ct)
}

fn bench(c: &mut Criterion) {
    let sizes = [1024usize, 4096, 16384];
    let provider = provider();
    let cfg = SesameConfig::default();

    for &size in &sizes {
        let body = payload(size);
        let body_hash = canonical::body_hash_hex(&body);
        let canon = canonical::request_canonical("POST", PATH, TS, NONCE, &body_hash, Some(SCOPE));
        let sig = tier1_hmac::sign(SIGN_KEY, &canon);

        // --- Tier 1 sign ---
        let mut g = c.benchmark_group("tier1_sign");
        g.throughput(Throughput::Bytes(size as u64));
        g.bench_with_input(BenchmarkId::from_parameter(size), &canon, |b, canon| {
            b.iter(|| tier1_hmac::sign(black_box(SIGN_KEY), black_box(canon)))
        });
        g.finish();

        // --- Tier 1 verify (sig + canonical recompute) ---
        let mut g = c.benchmark_group("tier1_verify");
        g.throughput(Throughput::Bytes(size as u64));
        g.bench_with_input(BenchmarkId::from_parameter(size), &body, |b, body| {
            b.iter(|| {
                let bh = canonical::body_hash_hex(black_box(body));
                let canon = canonical::request_canonical("POST", PATH, TS, NONCE, &bh, Some(SCOPE));
                tier1_hmac::verify(black_box(SIGN_KEY), &canon, black_box(&sig))
            })
        });
        g.finish();

        // --- Tier 2 authz ---
        let mut g = c.benchmark_group("tier2_authz");
        g.bench_with_input(BenchmarkId::from_parameter(size), &provider, |b, p| {
            b.iter(|| tier2_authz::authorize(black_box(p), "sas-east-01", SCOPE, Some("SportsFeed-East")))
        });
        g.finish();

        // --- Tier 3 seal ---
        let iv = [0u8; IV_LEN];
        let aad = tier3_aead::aad_for_headers(PROTOCOL_VERSION, "sas-east-01", TS, NONCE, Some(SCOPE));
        let mut g = c.benchmark_group("tier3_seal");
        g.throughput(Throughput::Bytes(size as u64));
        g.bench_with_input(BenchmarkId::from_parameter(size), &body, |b, body| {
            b.iter(|| tier3_aead::seal(black_box(&ENC_KEY), black_box(&iv), black_box(&aad), black_box(body)))
        });
        g.finish();

        // --- Tier 3 open ---
        let ct = tier3_aead::seal(&ENC_KEY, &iv, &aad, &body).unwrap();
        let mut g = c.benchmark_group("tier3_open");
        g.throughput(Throughput::Bytes(size as u64));
        g.bench_with_input(BenchmarkId::from_parameter(size), &ct, |b, ct| {
            b.iter(|| tier3_aead::open(black_box(&ENC_KEY), black_box(&iv), black_box(&aad), black_box(ct)))
        });
        g.finish();

        // --- Combined inbound: verify Tier1 + authz Tier2 + decrypt Tier3 ---
        let (headers3, body3) = signed_tier3_request(&body);
        let mut g = c.benchmark_group("combined_verify_open");
        g.throughput(Throughput::Bytes(size as u64));
        g.bench_with_input(BenchmarkId::from_parameter(size), &(headers3, body3), |b, (h, body3)| {
            b.iter_batched(
                || InMemoryReplayCache::new(300),
                |cache: InMemoryReplayCache| {
                    let ctx = RequestContext { method: "POST", path: PATH, target_channel: Some("SportsFeed-East") };
                    let r = sesame::verify_request(
                        &cfg, &provider, &cache as &dyn ReplayCache, &ctx,
                        black_box(h), black_box(body3), bench_now(), Tier::Three,
                    );
                    black_box(r.map(|v| v.plaintext.len()))
                },
                criterion::BatchSize::SmallInput,
            )
        });
        g.finish();

        // --- Combined outbound: Tier3 encrypt + Tier1 sign response ---
        let mut g = c.benchmark_group("combined_seal_sign");
        g.throughput(Throughput::Bytes(size as u64));
        g.bench_with_input(BenchmarkId::from_parameter(size), &body, |b, body| {
            let params = ResponseParams {
                signing_key_id: "pois-primary",
                correlation: "sig-001",
                scope: Some(SCOPE),
                tier: Tier::Three,
                enc_key_id: Some("enc-sportsfeed-2026q1"),
            };
            b.iter(|| sesame::sign_response(&cfg, &provider, &params, black_box(body), now()))
        });
        g.finish();
    }
}

criterion_group!(benches, bench);
criterion_main!(benches);
